UnderscoreRegex3.Replace(
    UnderscoreRegex2.Replace(
        UnderscoreRegex1.Replace(input, "$1_$2"), "$1_$2"), "_")
    .ToLower();

// Suggested: single-pass using string.Create
public static string Underscore(this string input)
{
    // Estimate max length (each char could gain an underscore)
    var sb = new StringBuilder(input.Length + 10);
    for (int i = 0; i < input.Length; i++)
    {
        char c = input[i];
